class Solution {
    public int bestClosingTime(String customers) {
        int n = customers.length();
        int[] penalty = new int[n + 1];
        for (int i = 0; i <= n; i++) {
            int y = 0, n_ = 0;
            for (int j = 0; j < i; j++) {
                if (customers.charAt(j) == 'Y') y++;
                else n_++;
            }
            for (int j = i; j < n; j++) {
                if (customers.charAt(j) == 'Y') y++;
                else n_++;
            }
            penalty[i] = y + n_;
        }
        return Arrays.stream(penalty).min().getAsInt();
    }
}
```

